sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {

    if (isLoading || !newValue)
        return;

    var ga = new GlideAjax(
        'Autoupdateborrowerdetails'
    );

    ga.addParam(
        'sysparm_name',
        'getDetails'
    );

    ga.addParam(
        'sysparm_user',
        newValue
    );

    ga.getXMLAnswer(function(response) {

        if (!response)
            return;

        var data = JSON.parse(response);

        g_form.setValue(
            'new_field_1',
            data.full_name
        );

        g_form.setValue(
            'contact_number',
            data.phone
        );

        g_form.setValue(
            'email',
            data.email
        );

    });

}
